import { motion, useScroll } from "motion/react";
import { useState, useEffect } from "react";
import { Menu, X } from "lucide-react";

const LOGO_BLACK = "data:image/png;base64,";

/** Drop this immediately after <Navbar /> in your page to offset the fixed bar */
export function NavbarSpacer() {
  return <div style={{ height: "4rem" }} aria-hidden="true" />;
}

export function Navbar() {
  const [menuOpen, setMenuOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const { scrollY } = useScroll();

  useEffect(() => {
    const unsubscribe = scrollY.on("change", (v) => setScrolled(v > 60));
    return unsubscribe;
  }, [scrollY]);

  useEffect(() => {
    if (scrolled) setMenuOpen(false);
  }, [scrolled]);

  const navLinks = [
    { label: "About",   href: "#manifesto" },
    { label: "Watch",   href: "#interviews" },
    { label: "Submit",  href: "#submissions" },
    { label: "Team",    href: "#team" },
    { label: "Partner", href: "#partnerships" },
  ];

  return (
    <motion.header
      className={`fixed top-0 left-0 right-0 z-[1000] transition-all duration-300 bg-white/95 backdrop-blur-[8px] ${
        scrolled
          ? "border-b border-black/10 shadow-sm"
          : "border-b border-transparent"
      }`}
      initial={{ y: -64, opacity: 0 }}
      animate={{ y: 0, opacity: 1 }}
      transition={{ duration: 0.6, ease: "easeOut" }}
    >
      <div className="afro-navbar-inner">
        <a href="#" className="afro-logo-link" aria-label="Afronated — Home">
          <img
            src={LOGO_BLACK}
            alt="Afronated"
            className="afro-navbar-logo"
          />
        </a>

        <nav className="afro-desktop-nav">
          {navLinks.map((link) => (
            <a key={link.label} href={link.href} className="afro-nav-link">
              {link.label}
              <span className="afro-nav-underline" />
            </a>
          ))}
        </nav>

        <button
          className="afro-hamburger"
          onClick={() => setMenuOpen(!menuOpen)}
          aria-label="Toggle menu"
        >
          {menuOpen ? <X className="w-5 h-5" /> : <Menu className="w-5 h-5" />}
        </button>
      </div>

      {menuOpen && (
        <motion.nav
          className="afro-mobile-nav"
          initial={{ opacity: 0, y: -6 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.18 }}
        >
          {navLinks.map((link) => (
            <a
              key={link.label}
              href={link.href}
              onClick={() => setMenuOpen(false)}
              className="afro-mobile-nav-link"
            >
              {link.label}
            </a>
          ))}
        </motion.nav>
      )}

      <style>{`
        .afro-navbar-inner {
          max-width: 1200px;
          margin: 0 auto;
          padding: 0 1.5rem;
          height: 4rem;
          display: flex;
          align-items: center;
          justify-content: space-between;
        }
        .afro-logo-link {
          display: flex;
          align-items: center;
          flex-shrink: 0;
          text-decoration: none;
        }
        .afro-navbar-logo {
          height: 2.2rem;
          width: auto;
          object-fit: contain;
          display: block;
        }
        .afro-desktop-nav {
          display: none;
          align-items: center;
          gap: 2rem;
        }
        .afro-nav-link {
          position: relative;
          font-size: 10px;
          letter-spacing: 0.25em;
          text-transform: uppercase;
          color: rgba(0,0,0,0.55);
          text-decoration: none;
          transition: color 0.2s;
        }
        .afro-nav-link:hover { color: #000; }
        .afro-nav-underline {
          position: absolute;
          bottom: -2px;
          left: 0;
          width: 0;
          height: 1px;
          background: #EF4444;
          transition: width 0.3s;
          display: block;
        }
        .afro-nav-link:hover .afro-nav-underline { width: 100%; }
        .afro-hamburger {
          display: block;
          padding: 0.375rem;
          background: none;
          border: none;
          cursor: pointer;
          color: #000;
          line-height: 0;
        }
        .afro-mobile-nav {
          background: #fff;
          border-top: 1px solid rgba(0,0,0,0.08);
          padding: 1.5rem;
          display: flex;
          flex-direction: column;
          gap: 1.25rem;
        }
        .afro-mobile-nav-link {
          font-size: 13px;
          letter-spacing: 0.2em;
          text-transform: uppercase;
          color: rgba(0,0,0,0.7);
          text-decoration: none;
          transition: color 0.2s;
        }
        .afro-mobile-nav-link:hover { color: #EF4444; }
        @media (min-width: 768px) {
          .afro-desktop-nav { display: flex; }
          .afro-hamburger   { display: none; }
          .afro-mobile-nav  { display: none !important; }
        }
      `}</style>
    </motion.header>
  );
}